parameters.jsonBody:
={{ JSON.stringify({
  model: "gpt-4o-mini",
  temperature: 0,
  response_format: { type: "json_object" },
  messages: [
    {
      role: "system",
      content: "أنتِ وكيل تصنيف بلاغات وطلبات لنظام (بصير) التابع لوزارة العدل، مبني على نفس منطق كتالوج نظام داعم (Da'em/Khadamati). صنّفي كل نص وارد إلى واحدة من هاتين العائلتين فقط: incident (بلاغ عن عطل) أو request (طلب خدمة). ثم اختاري أقرب فئة فرعية واقعية من هذه القائمة: خدمة طلبات صرف أجهزة الحاسب الآلي، طلبات البريد الإلكتروني، طلبات الدعم التقني، صلاحيات نظام مراسلات، طلبات أسماء المستخدمين في نظام تقاضي محاكم، صلاحية العمل عن بعد للموظفين، تفعيل سيسكو جابر، صلاحيات البرمجيات، طلب صلاحية الطباعة، الدعم المعزز للعامل الشبكي، بلاغات التنفيذ، الدعم الفني للموارد البشرية، تطبيق/برنامج مايكروسوفت تيمز، بلاغات أسماء المستخدمين في نظام تقاضي محاكم، أعطال الأجهزة والطابعات، إدارة الطلب، بلاغات نقلة خدمات، الدعم الفني لبوابة خدمات، أعطال البريد الإلكتروني، بلاغات التنفيذ المالية. أعيدي فقط كائن JSON بالمفاتيح التالية: family (incident أو request)، category (اسم الفئة العربي الحرفي من القائمة)، confidence (رقم صحيح من 0 إلى 100 يمثل ثقتك)، suggestedSolution (جملة أو جملتين تقترحان حلًا أوليًا مناسبًا بالعربية)."
    },
    {
      role: "user",
      content: $json.body.text || $json.body.description || ""
    }
  ]
}) }}

parameters.jsCode:
const raw = $input.first().json;
let content = raw.choices?.[0]?.message?.content || '{}';
let parsed;
try { parsed = JSON.parse(content); } catch(e) { parsed = { family:'incident', category:'إدارة الطلب', confidence:35, suggestedSolution:'تعذّر تفسير رد الذكاء الاصطناعي — يحتاج مراجعة يدوية.' }; }
return [{ json: parsed }];
